/*\

Dolive widget

\*/
(function(){

/*jslint node: true, browser: true */
/*global $tw: false */
"use strict";

var Widget = require("$:/core/modules/widgets/widget.js").widget;

var MyWidget = function(parseTreeNode,options) {
	this.initialise(parseTreeNode,options);
};

MyWidget.prototype = new Widget();

MyWidget.prototype.render = function(parent,nextSibling) {
	this.parentDomNode = parent;
	var text = this.wiki.getTiddlerText("test", "<empty>")
	var textNode = this.document.createTextNode(text);
	parent.insertBefore(textNode,nextSibling);
	this.domNodes.push(textNode);
};

exports.dolive = MyWidget;

})();

/*\
title: $:/plugins/custom/callLivecode
type: application/javascript
module-type: widget
exports: wikiscript
handler: tiddlyButton_Call
\*/
(function(){

/*jslint node: true, browser: true */
/*global $tw: false */
"use strict";

var Widget = require("$:/core/modules/widgets/widget.js").widget;

// Define the CallLivecode widget class
var CallLivecodeWidget = function(parseTreeNode, options) {
    this.initialise(parseTreeNode, options);
};

// Inherit from the base Widget class
CallLivecodeWidget.prototype = new Widget();

// Define the invokeAction method
CallLivecodeWidget.prototype.invokeAction = function(triggeringWidget, event) {
    // Compute and resolve attributes
    this.computeAttributes();
    var message = this.getAttribute("message", "Default Message");

    try {
        // Call the Livecode handler with the message
        var livecodeResult = liveCode.tiddlyButton_Call(message);

        // Update the "test" tiddler with the result
        $tw.wiki.addTiddler(new $tw.Tiddler({
            title: "test",
            text: livecodeResult || "Empty response from Livecode",
            type: "text/plain"
        }));
    } catch (e) {
        console.error("Error calling Livecode:", e);

        // Update the "test" tiddler with the error message
        $tw.wiki.addTiddler(new $tw.Tiddler({
            title: "test",
            text: "Error calling Livecode: " + e.message,
            type: "text/plain"
        }));
    }

    return true; // Indicate the action was handled
};

// Export the widget class
exports.wikiscript = CallLivecodeWidget;

})();

/*\

Hello, World widget

\*/
(function(){

/*jslint node: true, browser: true */
/*global $tw: false */
"use strict";

var Widget = require("$:/core/modules/widgets/widget.js").widget;

var MyWidget = function(parseTreeNode,options) {
	this.initialise(parseTreeNode,options);
};

/*
Inherit from the base widget class
*/
MyWidget.prototype = new Widget();

/*
Render this widget into the DOM
*/
MyWidget.prototype.render = function(parent,nextSibling) {
	this.parentDomNode = parent;
	var textNode = this.document.createTextNode("Hello, World!");
	parent.insertBefore(textNode,nextSibling);
	this.domNodes.push(textNode);
};

exports.hello = MyWidget;

})();

Let's start be defining a minimal widget which does nothing. It doesn't support any attributes, no child elements, and it doesn't output anything. The name of the widget will be `donothing`. If it does nothing, then how can we verify after writing the code that we accomplished anything? Well, let's see what happens when an undefined widget is referenced.

{{Undefined widget demo}}

Since we haven't written the code, the attempt to render the widget gives an undefined widget error. So we will know the donothing code accomplishes something if we don't get the undefined widget error when rendering.
